**Important:** `data` and `option` are JS properties — not HTML attributes.

```js
import '@lit-ui/charts/candlestick-chart';

const chart = document.querySelector('lui-candlestick-chart');
chart.data = [
  // [open, close, low, high] — NOT [open, high, low, close]!
  { label: '2024-01-01', ohlc: [100, 110, 95, 115], volume: 50000 },
  { label: '2024-01-02', ohlc: [110, 105, 102, 112], volume: 45000 },
  { label: '2024-01-03', ohlc: [105, 120, 103, 122], volume: 62000 },
];
```

```html
<!-- Show volume panel -->
<lui-candlestick-chart show-volume></lui-candlestick-chart>

<!-- Custom bull/bear colors -->
<lui-candlestick-chart bull-color="#00c853" bear-color="#ff1744"></lui-candlestick-chart>

<!-- MA with explicit colors -->
<lui-candlestick-chart moving-averages='[{"period":20,"color":"#f59e0b"},{"period":50,"color":"#8b5cf6","type":"ema"}]'></lui-candlestick-chart>

<!-- MA with CSS token defaults (omit color — auto-assigned --ui-chart-color-2, -3, -4...) -->
<lui-candlestick-chart moving-averages='[{"period":20},{"period":50,"type":"ema","showType":true}]'></lui-candlestick-chart>
<!-- Second MA above: legend shows "MA50 (EMA)" because showType is true -->
```

```tsx
// React
import { useRef, useEffect } from 'react';
function CandlestickChartDemo({ data }) {
  const ref = useRef(null);
  useEffect(() => {
    if (ref.current) ref.current.data = data;
  }, [data]);
  return <lui-candlestick-chart ref={ref} show-volume />;
}
```

```js
// Real-time streaming: append a new OHLC bar
chart.pushData({ label: '2024-01-04', ohlc: [120, 118, 115, 125], volume: 48000 });
```

```js
// NaN closes produce null MA gaps — they do NOT corrupt the MA window
chart.pushData({ label: '2024-01-03', ohlc: [105, NaN, 103, 122] });
// This bar's MA value will be null → rendered as a gap in the MA line
// Next valid close resumes MA calculation cleanly
```

```ts
// WARNING: ECharts order is [open, close, low, high]
// NOT the OHLC acronym order [open, high, low, close]
type OhlcBar = [
  open: number,
  close: number,  // ← second position, not fourth
  low: number,
  high: number    // ← fourth position, not second
];

type CandlestickBarPoint = {
  label: string;     // x-axis label — typically a date string
  ohlc: OhlcBar;     // [open, close, low, high]
  volume?: number;   // required if show-volume is set
};

type MAConfig = {
  period: number;        // number of bars in MA window (required)
  color?: string;        // optional — omit to use CSS token defaults (see Behavior Notes)
  type?: 'sma' | 'ema'; // default: 'sma'
  showType?: boolean;    // when true: legend label becomes "MA20 (EMA)" instead of "MA20"
};

// chart.data is CandlestickBarPoint[]
```

**CRITICAL:** `data`, `option`, `xCategories`, and `yCategories` are JS properties — they cannot be set as HTML attributes. Always assign via element reference.

```js
import '@lit-ui/charts/line-chart';

const chart = document.querySelector('lui-line-chart');
chart.data = [
  { name: 'Sales', data: [120, 200, 150, 80, 70, 110, 130] },
];
```

```tsx
// React — useRef + useEffect required for ALL .data assignments
import { useRef, useEffect } from 'react';

function LineChartDemo({ data }) {
  const ref = useRef(null);
  useEffect(() => {
    if (ref.current) ref.current.data = data;
  }, [data]);
  return <lui-line-chart ref={ref} smooth zoom />;
}
```

```js
const chart = document.querySelector('lui-line-chart');
chart.data = [{ name: 'Live', data: [] }];

setInterval(() => {
  chart.pushData(Math.random() * 100);
  // Multiple pushData() calls in the same animation frame are batched automatically
}, 100);
```

```js
// For line-chart and area-chart only: multi-series seriesIndex support
// chart.pushData(value, 1) routes to the second series
// See skills/line-chart and skills/area-chart for full multi-series API
```

Supported on: line, area, bar, pie, scatter, heatmap, candlestick.
NOT supported on: treemap (pushData() is a no-op with console.warn — reassign .data instead).

**Important:** `columns` and `data` are JS properties set imperatively (not HTML attributes).

```js
import '@lit-ui/data-table';

const table = document.querySelector('lui-data-table');
table.columns = [
  { accessorKey: 'name', header: 'Name', enableSorting: true },
  { accessorKey: 'email', header: 'Email' },
  { accessorKey: 'role', header: 'Role' },
  { accessorKey: 'status', header: 'Status' },
];
table.data = [
  { id: 1, name: 'Alice', email: 'alice@example.com', role: 'Admin', status: 'Active' },
  { id: 2, name: 'Bob', email: 'bob@example.com', role: 'Editor', status: 'Active' },
];
```

```html
<lui-data-table enable-selection show-column-picker></lui-data-table>
```

```js
// React example
import { useRef, useEffect } from 'react';

function MyTable({ data }) {
  const ref = useRef(null);
  useEffect(() => {
    if (ref.current) {
      ref.current.columns = columns;
      ref.current.data = data;
    }
  }, [data]);
  return <lui-data-table ref={ref} enable-selection />;
}
```

```js
// Row actions
table.rowActions = [
  { id: 'view', label: 'View', variant: 'default' },
  { id: 'edit', label: 'Edit', variant: 'default' },
  { id: 'delete', label: 'Delete', variant: 'destructive' },
];
// 1-2 actions render inline; 3+ use a kebab menu
```

```js
// Server-side data (sorting, filtering, pagination handled by server)
table.dataCallback = async (params, signal) => {
  const res = await fetch(`/api/users?${new URLSearchParams({
    page: String(params.pageIndex),
    size: String(params.pageSize),
    sort: JSON.stringify(params.sorting),
    filters: JSON.stringify(params.columnFilters),
  })}, { signal });
  const json = await res.json();
  return { data: json.rows, totalRowCount: json.total };
};
```

```js
// Inline row editing
table.columns = [
  { accessorKey: 'name', header: 'Name', meta: { editable: true, editType: 'text' } },
  { accessorKey: 'role', header: 'Role', meta: {
      editable: true, editType: 'select',
      editOptions: [{ label: 'Admin', value: 'Admin' }, { label: 'Editor', value: 'Editor' }]
  }},
];
// Combine with enable-row-editing attribute
```

```js
// CSV export
table.exportCsv({ filename: 'users.csv' });
table.exportCsv({ filename: 'selected.csv', selectedOnly: true });
```

```ts
type ColumnDef = {
  accessorKey: string;      // Maps to row data property
  header: string;           // Column header text
  enableSorting?: boolean;  // Enable sort on this column
  size?: number;            // Column width in pixels
  meta?: {
    filterType?: 'text' | 'select' | 'date';
    filterOptions?: { label: string; value: string }[];
    editable?: boolean;
    editType?: 'text' | 'select' | 'date';
    editOptions?: { label: string; value: string }[];
  };
};
```

Rules:
1. Add a `<script type="module">` tag importing the component.
2. Use HTML attributes for string/boolean/number values.
3. For object/array props, use a `<script>` to set via JS.

```html
<!DOCTYPE html>
<html>
<head>
  <script type="module">
    import '@lit-ui/button';
    import '@lit-ui/input';
    import '@lit-ui/data-table';

    // Set object/array props via JS
    const table = document.querySelector('lui-data-table');
    table.columns = [
      { key: 'name', label: 'Name' },
      { key: 'email', label: 'Email' }
    ];
    table.data = [{ name: 'Alice', email: 'alice@example.com' }];

    // Listen to custom events
    document.querySelector('lui-input').addEventListener('ui-change', (e) => {
      console.log('New value:', e.detail.value);
    });
  </script>
</head>
<body>
  <lui-input name="search" placeholder="Search..."></lui-input>
  <lui-button variant="primary">Search</lui-button>
  <lui-data-table></lui-data-table>
</body>
</html>
```

Rules:
1. Import the component as a side-effect at the top of the file (or in your entry point).
2. Use `class` (not `className`) for HTML attribute-based classes on custom elements in JSX.
3. String, boolean, and number props work as JSX attributes normally.
4. For object/array props, use a `ref` and set them imperatively in `useEffect`.
5. Listen to custom events with `addEventListener` in `useEffect`, or via the `onUiChange` prop if JSX types are provided.

```tsx
import { useEffect, useRef } from 'react';
import '@lit-ui/button';
import '@lit-ui/input';
import '@lit-ui/data-table';

function MyForm() {
  const tableRef = useRef(null);

  useEffect(() => {
    if (tableRef.current) {
      // Object/array props must be set via JS
      tableRef.current.columns = [
        { key: 'name', label: 'Name' },
        { key: 'email', label: 'Email' }
      ];
      tableRef.current.data = myData;
    }
  }, [myData]);

  useEffect(() => {
    const input = document.querySelector('lui-input');
    const handler = (e) => console.log(e.detail.value);
    input?.addEventListener('ui-change', handler);
    return () => input?.removeEventListener('ui-change', handler);
  }, []);

  return (
    <div>
      <lui-input name="email" type="email" placeholder="Email" />
      <lui-button variant="primary" type="submit">Submit</lui-button>
      <lui-data-table ref={tableRef} selectable />
    </div>
  );
}
```

TypeScript gotcha — declare custom elements for JSX:
```typescript
// In a .d.ts file or jsx.d.ts alongside the component
declare global {
  namespace JSX {
    interface IntrinsicElements {
      'lui-button': { variant?: string; disabled?: boolean; [key: string]: any };
      'lui-input': { name?: string; type?: string; placeholder?: string; [key: string]: any };
    }
  }
}
```

Rules:
1. Import the component as a side-effect in `<script setup>` or `main.ts`.
2. Use `v-bind` (`:prop`) for reactive string/boolean/number values.
3. For object/array props, use `:columns.prop="myColumns"` — the `.prop` modifier forces property (not attribute) binding.
4. Listen to custom events with `@ui-change="handler"`.
5. In Vue 3, custom elements work natively. No plugin needed.

```vue
<script setup>
import '@lit-ui/input';
import '@lit-ui/select';
import '@lit-ui/data-table';

const columns = [
  { key: 'name', label: 'Name' },
  { key: 'status', label: 'Status' }
];
const data = [{ name: 'Alice', status: 'active' }];

function onSearch(e) {
  console.log('Search:', e.detail.value);
}
</script>

<template>
  <lui-input
    name="search"
    placeholder="Search..."
    @ui-change="onSearch"
  />

  <!-- .prop modifier for object/array properties -->
  <lui-data-table
    :columns.prop="columns"
    :data.prop="data"
    selectable
  />
</template>
```

Suppress Vue unknown element warnings in `vite.config.ts`:
```typescript
// vite.config.ts
export default defineConfig({
  plugins: [
    vue({
      template: {
        compilerOptions: {
          isCustomElement: (tag) => tag.startsWith('lui-')
        }
      }
    })
  ]
});
```

Rules:
1. Import the component as a side-effect in `<script>`.
2. Use `on:ui-change={handler}` for custom event listeners.
3. For object/array props, bind via the DOM ref: `bind:this={el}` then set in `onMount`.
4. Boolean attributes work as in HTML: `<lui-button disabled>`.

```svelte
<script>
  import { onMount } from 'svelte';
  import '@lit-ui/input';
  import '@lit-ui/button';
  import '@lit-ui/data-table';

  let tableEl;
  let searchValue = '';

  const columns = [{ key: 'name', label: 'Name' }];
  const data = [{ name: 'Alice' }];

  onMount(() => {
    // Set object/array props after mount
    tableEl.columns = columns;
    tableEl.data = data;
  });

  function handleSearch(e) {
    searchValue = e.detail.value;
  }
</script>

<lui-input
  name="search"
  placeholder="Search..."
  on:ui-change={handleSearch}
/>

<lui-button variant="primary">Search</lui-button>

<lui-data-table bind:this={tableEl} selectable />
```

Rules:
1. Add `CUSTOM_ELEMENTS_SCHEMA` to your module or component `schemas` to suppress unknown element errors.
2. Import component side-effects in `main.ts` or in the component file.
3. Use `[attr.prop]="value"` for attribute binding, `[prop]="value"` for property binding.
4. For object/array props, use `[columns]="myColumns"` (property binding, not attribute).
5. Listen to custom events with `(ui-change)="handler($event)"`.

```typescript
// app.module.ts
import { NgModule, CUSTOM_ELEMENTS_SCHEMA } from '@angular/core';

@NgModule({
  schemas: [CUSTOM_ELEMENTS_SCHEMA]
})
export class AppModule {}
```

```typescript
// my-component.component.ts
import '@lit-ui/input';
import '@lit-ui/button';
import '@lit-ui/data-table';

@Component({
  template: `
    <lui-input
      name="search"
      [attr.placeholder]="'Search...'"
      (ui-change)="onSearch($event)"
    ></lui-input>

    <lui-button variant="primary">Search</lui-button>

    <!-- Property binding for objects/arrays -->
    <lui-data-table
      [columns]="columns"
      [data]="tableData"
      selectable
    ></lui-data-table>
  `
})
export class MyComponent {
  columns = [{ key: 'name', label: 'Name' }];
  tableData = [{ name: 'Alice' }];

  onSearch(e: CustomEvent) {
    console.log(e.detail.value);
  }
}
```

Rules:
1. HTML attributes only support strings. Objects and arrays become `"[object Object]"` if set as attributes.
2. Always set complex props via JavaScript property assignment on the element reference.
3. This applies to ALL frameworks for ALL object/array properties.

```javascript
// Always do this for objects/arrays:
const el = document.querySelector('lui-data-table');
el.columns = [{ key: 'name', label: 'Name' }];

// Never do this (broken):
// <lui-data-table columns="[{key: 'name'}]">  // WRONG — attribute is a string
```

**Important:** `data`, `xCategories`, and `yCategories` are JS properties — they CANNOT be set as HTML attributes.

```js
import '@lit-ui/charts/heatmap-chart';

const chart = document.querySelector('lui-heatmap-chart');
chart.xCategories = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'];
chart.yCategories = ['Morning', 'Afternoon', 'Evening'];
chart.data = [
  [0, 0, 85],   // Mon Morning: 85
  [1, 0, 72],   // Tue Morning: 72
  [2, 1, 40],   // Wed Afternoon: 40
  [4, 2, 91],   // Fri Evening: 91
];
```

```html
<!-- colorRange as comma-separated hex colors (min,max) -->
<lui-heatmap-chart color-range="#ffffff,#ef4444"></lui-heatmap-chart>
```

```tsx
// React — useRef + useEffect required for xCategories, yCategories, and data
import { useRef, useEffect } from 'react';
function HeatmapChartDemo({ xCats, yCats, data }) {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    ref.current.xCategories = xCats;
    ref.current.yCategories = yCats;
    ref.current.data = data;
  }, [xCats, yCats, data]);
  return <lui-heatmap-chart ref={ref} />;
}
```

```js
// Cell-update streaming: update a specific cell value
chart.pushData([2, 1, 55]); // Update Wed Afternoon to 55
// pushData on heatmap updates the cell in-place — not a rolling buffer
```

```ts
type HeatmapCell = [xIdx: number, yIdx: number, value: number];
// xIdx: integer index into xCategories array
// yIdx: integer index into yCategories array
// value: numeric value for color encoding

// chart.data is HeatmapCell[]
chart.data = [
  [0, 0, 85],  // xCategories[0], yCategories[0], value=85
  [1, 2, 43],  // xCategories[1], yCategories[2], value=43
];
```

